import type { ActiveSkillRow } from './types.js'
import {
  buildInstalledIntegrationContent,
  type IntegrationPluginRef,
} from './integration-loader.js'

/** Minimal assistant config for conditional loading */
interface AssistantSkillConfig {
  wallet_enabled?: boolean
  trading_enabled?: boolean
  disable_builtin_skills?: boolean
  /**
   * Plugins activated on this assistant. Only entries with `kind: 'integration'`
   * are inspected — used to load only the integration patterns the agent can
   * actually act on, instead of every provider in the catalog.
   */
  plugins?: ReadonlyArray<IntegrationPluginRef>
}

