// ── Integration skills (loaded only for installed integrations) ───────
// Content lives in integrations/<provider>/SKILL.md — loaded at startup by
// integration-loader.ts. The skill row is only emitted when the assistant has
// at least one integration plugin installed, and the rendered content covers
// only those installed providers (not the full 40-provider catalog).
// To add a new integration: create integrations/<provider>/SKILL.md and deploy.

interface SkillContent {
  slug: string
  name: string
  description: string
  content: string
}

/**
 * Cross-cutting guidance prepended to every integration skill bundle.
 *
 * Lives in code (not per-provider SKILL.md) because it applies to EVERY
 * integration that talks to humans — email, chat, calendar, CRM, etc.
 * When the user mentions a person by name ("email Eli", "DM Sarah",
 * "schedule a meeting with Alex"), the agent should resolve the name to
 * a real identifier BEFORE asking the user for one. Otherwise it punts
 * on trivially-answerable requests.
 */
const INTEGRATION_WORKFLOW_PREAMBLE = `## Resolving People by Name (applies to ALL integrations)

When the user mentions a person by **first name or nickname** ("email Eli",
"DM Sarah", "invite Alex to the meeting"), you must attempt to resolve the
name to a real identifier (email, user ID, handle) BEFORE asking the user
for one. Asking the user is the **last resort**, not the first step.

Resolution order (stop at the first match):

1. **Check \`## Memories\`** at the top of this system prompt. Prior turns
   may have stored "Eli → eli@acme.com" or "Sarah is our designer
   (@sarah_design on Slack)". Use it.
2. **Search the integration's own history.** Every messaging/email/CRM
   integration has a search or directory tool — call it with the name:
   - Gmail → \`search-emails\` with \`q="from:Eli OR to:Eli"\`, then read
     the top result's \`from\` header for the real address
   - Slack → \`list-users\` and match on \`real_name\` or \`display_name\`
   - Discord → \`list-members(guild_id)\` and match on username
   - HubSpot/Salesforce/Pipedrive → search contacts by name
   - Google Calendar → \`search-events\` for past meetings with that name
3. **Only then**, if no match, ask the user — and be specific:
   "I couldn't find anyone named Eli in your recent emails. What's their
   email address?"

### Rules
- NEVER ask for an email/handle on the first turn if you haven't searched yet
- If multiple matches, pick the most recent one and tell the user which you used ("Sending to eli.chen@acme.com — the Eli you last emailed yesterday. Different person? Let me know.")
- If the user provides a **full email or handle** (eli@acme.com, @sarah), skip resolution and use it directly
- Never invent an email address — if search fails, ask

---

`

function buildIntegrationWorkflowSkill(
  plugins?: ReadonlyArray<IntegrationPluginRef>,
): SkillContent | null {
  if (!plugins || plugins.length === 0) return null
  const providerContent = buildInstalledIntegrationContent(plugins)
  if (!providerContent) return null
  return {
    slug: 'lucid-integration-workflow',
    name: 'Integration Workflow Patterns',
    description:
      'Teaches the agent how to use the OAuth integrations installed on this assistant.',
    content: INTEGRATION_WORKFLOW_PREAMBLE + providerContent,
  }
}


