// ── Selection logic ──────────────────────────────────────────────────

/**
 * Get built-in skills as ActiveSkillRow[], ready to merge with DB skills.
 *
 * Conditional loading:
 * - market-intelligence: always (every agent gets market data tool awareness)
 * - integration-workflow: only when at least one integration is installed,
 *   and only for the installed providers (not the full 40-provider catalog)
 * - swap-direction: when wallet or trading enabled
 * - swap-execution + cross-chain-funding: when trading enabled
 * - web3-reader: when wallet or trading enabled
 * - web3-operator: from DB catalog (when trading enabled + org installs it)
 */
export function getBuiltinSkills(config?: AssistantSkillConfig): ActiveSkillRow[] {
  if (config?.disable_builtin_skills) {
    return []
  }

  const skills: SkillContent[] = [marketIntelligenceSkill]

  // Integration workflow — only when at least one integration is installed
  const integrationSkill = buildIntegrationWorkflowSkill(config?.plugins)
  if (integrationSkill) skills.push(integrationSkill)

  // Swap direction safety — loaded when wallet or trading is enabled
  if (config?.wallet_enabled || config?.trading_enabled) {
    skills.push(swapDirectionSkill)
  }

  if (config?.trading_enabled) {
    skills.push(swapExecutionSkill)
    skills.push(crossChainFundingSkill)
    // Polymarket skill (trading + hedge) now DB-managed via skill_catalog
    // Trading agents also get wallet read guidance (tool chaining, search-first)
    skills.push(web3ReaderSkill)
  }

  if (!config?.trading_enabled && config?.wallet_enabled) {
    skills.push(web3ReaderSkill)
  }

  return skills.map((skill, i) => ({
    skill_slug: skill.slug,
    skill_name: skill.name,
    skill_description: skill.description,
    sanitized_content: skill.content,
    frontmatter: {},
    sort_order: 1000 + i,
    content_chars: skill.content.length,
    selection_meta: {
      source: 'builtin',
      reason: 'builtin',
    },
  }))
}
